void OnTcpListen( dword socket, long result)
{
  DWORD clientHandle;
  // Accept the connection
  clientHandle = TcpAccept( socket );

  tlsOpen(clientHandle);

  // choose one of these two options:
  tlsAuthenticateAsServer(clientHandle,"ServerCertificateCommonName"); // certificate based TLS handshake
  // or
  tlsAuthenticateAsServer(clientHandle, "PreSharedKeyName”); // Pre Shared Key based TLS handshake

  if ((tlsGetLastError(clientHandle) != 0) &&
  (tlsGetLastError(clientHandle) != 997))
  {
    // an error occurred
    return;
  }
}
